verbs.source:
verb :look() rxd {
  return { id: this, title: this.name, description: this.description, api_version: this.api_version, tools: ["inspect(id, opts?)", "search(query, opts?)", "create(parent, opts?)", "chparent(id, parent, opts?)", "recycle(id, opts?)", "set_property(id, name, value, opts?)"] };
}

verb :inspect(id, opts) rxd {
  // Builder surface check: wizard, or descendant of $builder.
  if (!has_flag(actor, "wizard")) {
    if (actor == $builder) { raise { code: "E_PERM", message: "builder class surface required", value: { actor: actor, surface: $builder } }; }
    if (!isa(actor, $builder)) { raise { code: "E_PERM", message: "builder class surface required", value: { actor: actor, surface: $builder } }; }
  }
  // Structure/data view: owner, flags, parent, children, instances, location,
  // contents, and property summaries. No source output.
  return authoring_inspect(id, opts, false);
}

verb :search(query, opts) rxd {
  if (!has_flag(actor, "wizard")) {
    if (actor == $builder) { raise { code: "E_PERM", message: "builder class surface required", value: { actor: actor, surface: $builder } }; }
    if (!isa(actor, $builder)) { raise { code: "E_PERM", message: "builder class surface required", value: { actor: actor, surface: $builder } }; }
  }
  // Bounded actor-scoped search across object names and property channels.
  // Source channels are reserved for the programmer surface.
  return authoring_search(query, opts, false);
}

verb :create(parent, opts) rxd {
  if (!has_flag(actor, "wizard")) {
    if (actor == $builder) { raise { code: "E_PERM", message: "builder class surface required", value: { actor: actor, surface: $builder } }; }
    if (!isa(actor, $builder)) { raise { code: "E_PERM", message: "builder class surface required", value: { actor: actor, surface: $builder } }; }
  }
  // Creates an object owned by the invoking actor. There is intentionally no
  // owner option on the builder surface; creating for another actor is wizard
  // administration, not delegated building.
  let result = builder_create_object(parent, opts);
  observe({ type: "builder_created", actor: actor, id: result["id"], parent: parent, ts: now() });
  return result;
}

verb :chparent(id, parent, opts) rxd {
  if (!has_flag(actor, "wizard")) {
    if (actor == $builder) { raise { code: "E_PERM", message: "builder class surface required", value: { actor: actor, surface: $builder } }; }
    if (!isa(actor, $builder)) { raise { code: "E_PERM", message: "builder class surface required", value: { actor: actor, surface: $builder } }; }
  }
  let result = builder_chparent(id, parent, opts);
  if (result["ok"] && !result["dry_run"]) {
    observe({ type: "builder_chparented", actor: actor, id: id, parent: parent, ts: now() });
  }
  return result;
}

verb :recycle(id, opts) rxd {
  // Surface gate. The wrapper is direct_callable for MCP/REST tool use,
  // which would otherwise expose it to non-builder owners. Mirror the
  // builder-class requirement that the other $builder verbs (:inspect,
  // :create, :chparent, :set_property, :recycle_command) enforce, so the
  // documented surface (catalogs/prog/README.md) holds across every
  // call path. the_perm below still narrows from "any builder" to
  // "owner-or-wizard" — the gate adds a class-membership precondition,
  // it doesn't replace the perm check.
  if (!has_flag(actor, "wizard")) {
    if (actor == $builder) { raise { code: "E_PERM", message: "builder class surface required", value: { actor: actor, surface: $builder } }; }
    if (!isa(actor, $builder)) { raise { code: "E_PERM", message: "builder class surface required", value: { actor: actor, surface: $builder } }; }
  }
  // The substrate `recycle()` builtin gates on the verb's effective
  // principal (progr); this wrapper is catalog-owned, so progr is
  // wizard. Two layers of defense are needed.
  //
  // Layer 1 — actor-side authority gate (LambdaCore @recycle pattern):
  // route through the_perm so the auth rule lives in one place.
  "the_perm":requires_perm(actor, id, "only the owner or a wizard can recycle this object");
  // Layer 2 — strip user-intent wizard opts before forwarding. The
  // substrate also gates force_reserved on actor (defense in depth at
  // the substrate layer), but stripping here keeps the smuggle vector
  // out of the substrate's parser entirely. force_reserved is the
  // exclusive concern of $wiz:force_recycle.
  let safe_opts = {};
  if (typeof(opts) == "map") {
    for k in keys(opts) {
      if (k != "force_reserved") { safe_opts[k] = opts[k]; }
    }
  }
  let result = recycle(id, safe_opts);
  if (result["ok"] && !result["dry_run"]) {
    observe({ type: "builder_recycled", actor: actor, id: id, ts: now() });
  }
  return result;
}

verb :recycle_command(dobjstr) rxd {
  // LambdaCore $builder:@recycle (#630), faithfully ported. Divergences
  // (1)–(2) are called out where they appear; aside from those the verb
  // is line-for-line equivalent.
  //
  // Surface gate. LambdaCore reaches @recycle only via the actor's
  // parent chain (verb resolution), so a non-builder cannot reach it.
  // woo's `direct_callable: true` exposes the verb to direct calls
  // (MCP tools, REST), which would otherwise bypass the chain. Mirror
  // the gate the other $builder surface verbs (:inspect, :create,
  // :chparent, :set_property) use.
  if (!has_flag(actor, "wizard")) {
    if (actor == $builder) { raise { code: "E_PERM", message: "builder class surface required", value: { actor: actor, surface: $builder } }; }
    if (!isa(actor, $builder)) { raise { code: "E_PERM", message: "builder class surface required", value: { actor: actor, surface: $builder } }; }
  }
  if (typeof(dobjstr) != "string" || dobjstr == "") {
    tell(actor, "Usage: @recycle <object>");
    return null;
  }
  // L2 Original: dobj = player:my_match_object(dobjstr).
  // Divergence (1): woo's matcher is on $match (spec/semantics/match.md
  // MA1), not on the player; the MA2 resolution rule mirrors LambdaCore's
  // $string_utils:match_object.
  let dobj = $match:match_object(dobjstr);
  // L5-6 Original: $command_utils:object_match_failed.
  if ($command_utils:object_match_failed(dobj, dobjstr)) {
    return null;
  }
  // L7-8 Self-recycle. Original reads $wiz_utils.suicide_string; woo
  // doesn't carry that property, so a static line stands in.
  if (actor == dobj) {
    tell(actor, "You can't recycle yourself.");
    return null;
  }
  // L9-10 Original: !$perm_utils:controls(player, dobj) -> notify(E_PERM).
  // Divergence (2): woo routes the same owner-or-wizard rule through
  // the_perm so the auth gate lives in one place; the_perm raises E_PERM
  // and the chat layer renders it.
  "the_perm":requires_perm(actor, dobj, "only the owner or a wizard can recycle this object");
  // L1 set_task_perms(player) is omitted: woo's substrate authority gates
  // on `actor` and `progr` directly, and recycle() re-checks RC2 on entry.
  // L12-17 Capture name, recycle, notify with paste-able id.
  let name = dobj.name;
  let result = recycle(dobj, {});
  if (typeof(result) != "map" || !result["ok"]) {
    tell(actor, "Recycle failed: " + to_string(result));
    return result;
  }
  tell(actor, name + " (#" + dobj + ") recycled.");
  return result;
}

verb :set_property(id, name, value, opts) rxd {
  if (!has_flag(actor, "wizard")) {
    if (actor == $builder) { raise { code: "E_PERM", message: "builder class surface required", value: { actor: actor, surface: $builder } }; }
    if (!isa(actor, $builder)) { raise { code: "E_PERM", message: "builder class surface required", value: { actor: actor, surface: $builder } }; }
  }
  // Ordinary data value setting. This does not change verb source, property
  // perms, executable metadata, wizard/programmer flags, or ownership.
  // Existence probe — catalog must reject E_PROPNF here, otherwise
  // setPropChecked's owner/wizard auto-create branch would let the
  // wizard-installed verb create the property silently.
  let info = null;
  try {
    info = property_info(id, name);
  } except err {
    if (err["code"] == "E_PROPNF") {
      raise { code: "E_PROPNF", message: "property not found: " + name, value: { obj: id, property: name } };
    }
    raise err;
  }
  // Actor-side canWriteProperty (mirrors world.ts:canWriteProperty).
  // The substrate-side check uses `progr` (which is $wiz here, since
  // the verb is wizard-installed) and would always pass — a builder
  // without "w" perm would otherwise smuggle writes through the
  // wizard-owned wrapper. This gate stays in lockstep with the gate
  // builder_set_property used to enforce internally.
  let allowed = false;
  if (has_flag(actor, "wizard")) { allowed = true; }
  if (info["owner"] == actor) { allowed = true; }
  if (str_index(info["perms"], "w") > 0) { allowed = true; }
  if (!allowed) {
    raise { code: "E_PERM", message: "permission denied", value: { actor: actor, obj: id, property: name } };
  }
  // SET_PROP opcode (DSL `obj.(name) = value`).
  id.(name) = value;
  let info_after = property_info(id, name);
  return { ok: true, id: id, name: name, version: info_after["version"], info: info_after };
}

verb :contents_command(dobjstr) rxd {
  // LambdaCore $builder:@contents (#630), faithfully ported. Surface
  // gate added because the verb is direct_callable (see :recycle and
  // :recycle_command for the same justification).
  if (!has_flag(actor, "wizard")) {
    if (actor == $builder) { raise { code: "E_PERM", message: "builder class surface required", value: { actor: actor, surface: $builder } }; }
    if (!isa(actor, $builder)) { raise { code: "E_PERM", message: "builder class surface required", value: { actor: actor, surface: $builder } }; }
  }
  // L3-7 Empty dobjstr defaults to the actor's location.
  let dobj = null;
  if (typeof(dobjstr) != "string" || dobjstr == "") {
    dobj = location(actor);
    if (dobj == null) {
      tell(actor, "Usage: @contents <object>");
      return null;
    }
  } else {
    dobj = $match:match_object(dobjstr);
  }
  if ($command_utils:object_match_failed(dobj, dobjstr)) {
    return null;
  }
  // L10-16. `name(<paste-able id>) contains:` then names_of(contents).
  let id_str = dobj;
  if (!str_starts(id_str, "$")) { id_str = "#" + id_str; }
  let contents_list = contents(dobj);
  if (length(contents_list) > 0) {
    tell(actor, dobj.name + "(" + id_str + ") contains:");
    tell(actor, $string_utils:names_of(contents_list));
  } else {
    tell(actor, dobj.name + "(" + id_str + ") contains nothing.");
  }
  return contents_list;
}

verb :parents_command(dobjstr) rxd {
  // LambdaCore $builder:@parents (#630), faithfully ported. Lists the
  // object and its ancestor chain up to $root.
  if (!has_flag(actor, "wizard")) {
    if (actor == $builder) { raise { code: "E_PERM", message: "builder class surface required", value: { actor: actor, surface: $builder } }; }
    if (!isa(actor, $builder)) { raise { code: "E_PERM", message: "builder class surface required", value: { actor: actor, surface: $builder } }; }
  }
  if (typeof(dobjstr) != "string" || dobjstr == "") {
    tell(actor, "Usage: @parents <object>");
    return null;
  }
  let dobj = $match:match_object(dobjstr);
  if ($command_utils:object_match_failed(dobj, dobjstr)) {
    return null;
  }
  // Walk parents() (woo builtin returns the full ancestor chain).
  let chain = [dobj] + parents(dobj);
  tell(actor, $string_utils:names_of(chain));
  return chain;
}

verb :kids_command(dobjstr) rxd {
  // LambdaCore $builder:@kids (#630), faithfully ported. Lists the
  // direct children of an object.
  if (!has_flag(actor, "wizard")) {
    if (actor == $builder) { raise { code: "E_PERM", message: "builder class surface required", value: { actor: actor, surface: $builder } }; }
    if (!isa(actor, $builder)) { raise { code: "E_PERM", message: "builder class surface required", value: { actor: actor, surface: $builder } }; }
  }
  if (typeof(dobjstr) != "string" || dobjstr == "") {
    tell(actor, "Usage: @kids <object>");
    return null;
  }
  let thing = $match:match_object(dobjstr);
  if ($command_utils:object_match_failed(thing, dobjstr)) {
    return null;
  }
  let kids = children(thing);
  let id_str = thing;
  if (!str_starts(id_str, "$")) { id_str = "#" + id_str; }
  let n = length(kids);
  if (n > 0) {
    let suffix = "s";
    if (n == 1) { suffix = ""; }
    tell(actor, thing.name + "(" + id_str + ") has " + to_string(n) + " kid" + suffix + ".");
    tell(actor, $string_utils:names_of(kids));
  } else {
    tell(actor, thing.name + "(" + id_str + ") has no kids.");
  }
  return kids;
}

verb :create_command(argstr) rxd {
  // LambdaCore $builder:@create (#630), faithfully ported. Parses
  // `@create <parent> named <name>[,<alias>,...]` (and the `called`
  // synonym) into a builder_create_object call.
  //
  // Surface gate.
  if (!has_flag(actor, "wizard")) {
    if (actor == $builder) { raise { code: "E_PERM", message: "builder class surface required", value: { actor: actor, surface: $builder } }; }
    if (!isa(actor, $builder)) { raise { code: "E_PERM", message: "builder class surface required", value: { actor: actor, surface: $builder } }; }
  }
  let usage = "Usage: @create <parent-class> named <name>[,<alias>,...]";
  if (typeof(argstr) != "string" || argstr == "") {
    tell(actor, usage);
    return null;
  }
  // Locate the keyword. " called " is an accepted synonym (LambdaCore L5).
  let kw = " named ";
  let kw_pos = str_index(argstr, kw);
  if (kw_pos == 0) {
    kw = " called ";
    kw_pos = str_index(argstr, kw);
  }
  if (kw_pos == 0) {
    tell(actor, usage);
    return null;
  }
  let parentstr = str_trim(str_slice(argstr, 1, kw_pos - 1));
  let namestr = str_trim(str_slice(argstr, kw_pos + length(kw)));
  if (parentstr == "" || namestr == "") {
    tell(actor, usage);
    return null;
  }
  // Resolve parent via $match (handles `#xxx`, `$xxx`, and the standard
  // tier walk). `$match:match_object` covers LambdaCore's :literal_object
  // + :my_match_object combo.
  let parent = $match:match_object(parentstr);
  if ($command_utils:object_match_failed(parent, parentstr)) {
    return null;
  }
  // Names: comma-split. First = display name; rest = aliases. LambdaCore
  // also supports `name-and-alias,alias,…` and `name:alias,…` shapes via
  // $building_utils:set_names — those are deferred until ported here.
  let names = str_split(namestr, ",");
  let trimmed_names = [];
  for n in names {
    let t = str_trim(n);
    if (t != "") { trimmed_names = trimmed_names + [t]; }
  }
  if (length(trimmed_names) == 0) {
    tell(actor, usage);
    return null;
  }
  let display_name = trimmed_names[1];
  let aliases = [];
  let total = length(trimmed_names);
  if (total > 1) {
    for i in [2..total] {
      aliases = aliases + [trimmed_names[i]];
    }
  }
  let opts = { name: display_name };
  if (length(aliases) > 0) { opts["aliases"] = aliases; }
  let result = builder_create_object(parent, opts);
  if (typeof(result) != "map" || !result["ok"]) {
    tell(actor, "Create failed: " + to_string(result));
    return result;
  }
  let new_id = result["id"];
  let id_str = new_id;
  if (!str_starts(id_str, "$")) { id_str = "#" + id_str; }
  let parent_id_str = parent;
  if (!str_starts(parent_id_str, "$")) { parent_id_str = "#" + parent_id_str; }
  let aka = "";
  if (length(aliases) > 0) { aka = " (aka " + str_join(aliases, ", ") + ")"; }
  tell(actor, "You now have " + display_name + aka + " with object number " + id_str + " and parent " + parent.name + " (" + parent_id_str + ").");
  // Move the new object into the actor's inventory, mirroring LambdaCore L42
  // (`move(object, player)`). builder_create_object doesn't auto-place;
  // moveto is a substrate builtin that runs the standard move chain.
  try { moveto(new_id, actor); } except err { /* :accept refused; leave at $nowhere. */ }
  observe({ type: "builder_created", actor: actor, id: new_id, parent: parent, ts: now() });
  return result;
}

verb :set_command(dobjstr, iobjstr) rxd {
  // LambdaCore $builder:@set (#630), faithfully ported. Parses
  // `@set <obj>.<prop> to <value>` (and `at` synonym). LambdaCore
  // L37-39 explicitly checks `has_property(dobj, prop)` before the
  // assignment so this verb does not silently create properties; the
  // inline body below mirrors that with an explicit property_info()
  // probe before the SET_PROP write.
  //
  // Surface gate.
  if (!has_flag(actor, "wizard")) {
    if (actor == $builder) { raise { code: "E_PERM", message: "builder class surface required", value: { actor: actor, surface: $builder } }; }
    if (!isa(actor, $builder)) { raise { code: "E_PERM", message: "builder class surface required", value: { actor: actor, surface: $builder } }; }
  }
  let usage = "Usage: @set <object>.<property> to <value>";
  if (typeof(dobjstr) != "string" || dobjstr == "") {
    tell(actor, usage);
    return null;
  }
  let spec = $code_utils:parse_propref(dobjstr);
  if (typeof(spec) != "list") {
    tell(actor, "Property " + dobjstr + " not found.");
    return null;
  }
  let obj_str = spec[1];
  let prop = spec[2];
  let dobj = $match:match_object(obj_str);
  if ($command_utils:object_match_failed(dobj, obj_str)) {
    return null;
  }
  // Parse the `to <value>` tail. iobjstr may be quoted ("…"), an integer,
  // a float, an objref literal (`#xxx` / `$xxx`), or a bare string;
  // $string_utils:to_value figures it out. Empty value clears to ""
  // (LambdaCore L21-26).
  let value = "";
  if (typeof(iobjstr) == "string" && str_trim(iobjstr) != "") {
    let parsed = $string_utils:to_value(iobjstr);
    if (!parsed[1]) {
      tell(actor, "Could not parse: " + iobjstr);
      return null;
    }
    value = parsed[2];
  }
  let id_str = dobj;
  if (!str_starts(id_str, "$")) { id_str = "#" + id_str; }
  // Inline existence check + actor-side perm check + SET_PROP; mirrors
  // builder_set_property's pre-substrate auth and the no-auto-create
  // convention. See $builder:set_property for why both gates exist.
  let info = null;
  try {
    info = property_info(dobj, prop);
  } except err {
    if (err["code"] == "E_PROPNF") {
      tell(actor, "That object does not define that property.");
      return err;
    }
    tell(actor, "Unable to check " + id_str + "." + prop + ": " + err["message"]);
    return err;
  }
  let allowed = false;
  if (has_flag(actor, "wizard")) { allowed = true; }
  if (info["owner"] == actor) { allowed = true; }
  if (str_index(info["perms"], "w") > 0) { allowed = true; }
  if (!allowed) {
    tell(actor, "Permission denied: " + id_str + "." + prop);
    return { code: "E_PERM", message: "permission denied", value: { actor: actor, obj: dobj, property: prop } };
  }
  try {
    dobj.(prop) = value;
  } except err {
    tell(actor, "Unable to set " + id_str + "." + prop + ": " + err["message"]);
    return err;
  }
  let display = to_string(value);
  if (typeof(value) == "string") {
    let q = str_char(34);
    display = q + value + q;
  }
  tell(actor, "Property " + id_str + "." + prop + " set to " + display + ".");
  return { ok: true, id: dobj, name: prop, value: value };
}

verb :look() rxd {
  return { id: this, title: this.name, description: this.description, api_version: this.api_version, tools: ["inspect(id, opts?)", "resolve_verb(id, descriptor)", "list_verb(id, descriptor, opts?)", "search(query, opts?)", "install_verb(id, descriptor, source, opts?)", "set_verb_info(id, descriptor, opts?)", "set_property_info(id, name, opts?)", "edit_verb(id, descriptor, opts?)", "trace(id, descriptor, opts?)", "eval(source, opts?)", "force_recycle(id, opts?)  [wizard-only]"] };
}

verb :inspect(id, opts) rxd {
  if (!has_flag(actor, "wizard")) {
    if (actor == $programmer) { raise { code: "E_PERM", message: "programmer class surface required", value: { actor: actor, surface: $programmer } }; }
    if (!isa(actor, $programmer)) { raise { code: "E_PERM", message: "programmer class surface required", value: { actor: actor, surface: $programmer } }; }
    if (!has_flag(actor, "programmer")) { raise { code: "E_PERM", message: "programmer flag required", value: actor }; }
  }
  // Source-aware call-tree view with read filters: parent/features walk, own
  // and inherited verbs/properties, slots, impact hints, and optional readable
  // source summaries. No bytecode.
  return authoring_inspect(id, opts, true);
}

verb :resolve_verb(id, descriptor) rxd {
  // Programmer surface check: wizard, or programmer-flagged descendant of
  // this surface class.
  if (!has_flag(actor, "wizard")) {
    if (actor == $programmer) {
      raise { code: "E_PERM", message: "programmer class surface required", value: { actor: actor, surface: $programmer } };
    }
    if (!isa(actor, $programmer)) {
      raise { code: "E_PERM", message: "programmer class surface required", value: { actor: actor, surface: $programmer } };
    }
    if (!has_flag(actor, "programmer")) {
      raise { code: "E_PERM", message: "programmer flag required", value: actor };
    }
  }
  let walk = [];
  let definer = null;
  if (typeof(descriptor) == "number") {
    let own = verbs(id);
    let matched = false;
    if (descriptor >= 1) { if (descriptor <= length(own)) { matched = true; } }
    walk = walk + [{ id: id, kind: "slot", slot: descriptor, matched: matched }];
    if (!matched) {
      raise { code: "E_VERBNF", message: "verb slot not found", value: { obj: id, slot: descriptor, actor: actor } };
    }
    definer = id;
  } else {
    let chain = [id] + parents(id);
    for class_ref in chain {
      if (definer == null) {
        let class_verbs = verbs(class_ref);
        let class_match = false;
        for n in class_verbs { if (n == descriptor) { class_match = true; } }
        walk = walk + [{ id: class_ref, kind: "parent", matched: class_match }];
        if (class_match) { definer = class_ref; }
      }
    }
    if (definer == null) {
      raise { code: "E_VERBNF", message: "verb not found", value: { obj: id, name: descriptor, actor: actor } };
    }
  }
  let info = verb_info(definer, descriptor);
  let source = verb_code(definer, descriptor);
  return {
    name: info["name"],
    slot: info["slot"],
    aliases: info["aliases"],
    definer: definer,
    owner: info["owner"],
    perms: info["perms"],
    arg_spec: info["arg_spec"],
    version: info["version"],
    direct_callable: info["direct_callable"],
    tool_exposed: info["tool_exposed"],
    readable: true,
    source: source,
    line_map: {},
    walk: walk
  };
}

verb :list_verb(id, descriptor, opts) rxd {
  // Return readable source and metadata for one ordered verb slot. This is
  // source-level only: no bytecode, opcode, literal-pool, or VM detail.
  if (!has_flag(actor, "wizard")) {
    if (actor == $programmer) {
      raise { code: "E_PERM", message: "programmer class surface required", value: { actor: actor, surface: $programmer } };
    }
    if (!isa(actor, $programmer)) {
      raise { code: "E_PERM", message: "programmer class surface required", value: { actor: actor, surface: $programmer } };
    }
    if (!has_flag(actor, "programmer")) {
      raise { code: "E_PERM", message: "programmer flag required", value: actor };
    }
  }
  let include_source = true;
  if (typeof(opts) == "map") { if (has(opts, "include_source")) { include_source = opts["include_source"]; } }
  let walk = [];
  let definer = null;
  if (typeof(descriptor) == "number") {
    let own = verbs(id);
    let matched = false;
    if (descriptor >= 1) { if (descriptor <= length(own)) { matched = true; } }
    walk = walk + [{ id: id, kind: "slot", slot: descriptor, matched: matched }];
    if (!matched) {
      raise { code: "E_VERBNF", message: "verb slot not found", value: { obj: id, slot: descriptor, actor: actor } };
    }
    definer = id;
  } else {
    let chain = [id] + parents(id);
    for class_ref in chain {
      if (definer == null) {
        let class_verbs = verbs(class_ref);
        let class_match = false;
        for n in class_verbs { if (n == descriptor) { class_match = true; } }
        walk = walk + [{ id: class_ref, kind: "parent", matched: class_match }];
        if (class_match) { definer = class_ref; }
      }
    }
    if (definer == null) {
      raise { code: "E_VERBNF", message: "verb not found", value: { obj: id, name: descriptor, actor: actor } };
    }
  }
  let info = verb_info(definer, descriptor);
  let result = {
    name: info["name"],
    slot: info["slot"],
    aliases: info["aliases"],
    definer: definer,
    owner: info["owner"],
    perms: info["perms"],
    arg_spec: info["arg_spec"],
    version: info["version"],
    direct_callable: info["direct_callable"],
    tool_exposed: info["tool_exposed"],
    readable: true,
    walk: walk
  };
  if (include_source) {
    result["source"] = verb_code(definer, descriptor);
    result["line_map"] = {};
  }
  return result;
}

