verb :install_verb(id, descriptor, source, opts) rxd {
  // Programmer surface check.
  if (!has_flag(actor, "wizard")) {
    if (actor == $programmer) { raise { code: "E_PERM", message: "programmer class surface required", value: { actor: actor, surface: $programmer } }; }
    if (!isa(actor, $programmer)) { raise { code: "E_PERM", message: "programmer class surface required", value: { actor: actor, surface: $programmer } }; }
    if (!has_flag(actor, "programmer")) { raise { code: "E_PERM", message: "programmer flag required", value: actor }; }
  }
  // Validate options. opts.perms is rejected — the source header is canonical.
  let dry_run = false;
  let mode = "upsert";
  let expected_version = null;
  if (typeof(opts) == "map") {
    if (has(opts, "perms")) {
      let fail_perms = { ok: false, dry_run: false, slot: 0, version: 0, diagnostics: [{ severity: "error", code: "E_INVARG", message: "opts.perms is not accepted; verb source header is canonical" }] };
      observe({ type: "programmer_check_failed", actor: actor, id: id, verb: descriptor, diagnostics: fail_perms["diagnostics"], dry_run: false, ts: now() });
      return fail_perms;
    }
    if (has(opts, "dry_run")) { dry_run = opts["dry_run"]; }
    if (has(opts, "mode")) { mode = opts["mode"]; }
    if (has(opts, "expected_version")) { expected_version = opts["expected_version"]; }
  }
  if (mode != "upsert" && mode != "define" && mode != "set_code") {
    raise { code: "E_INVARG", message: "unknown install mode", value: mode };
  }
  // Discover existing verb (own slot only).
  let existing = null;
  let existing_version = null;
  let existing_slot = 0;
  try {
    let info = verb_info(id, descriptor);
    existing = info;
    existing_version = info["version"];
    existing_slot = info["slot"];
  } except err { existing = null; }
  if (mode == "define" && existing != null) {
    raise { code: "E_INVARG", message: "verb already exists", value: { obj: id, descriptor: descriptor } };
  }
  if (mode == "set_code" && existing == null) {
    raise { code: "E_VERBNF", message: "verb not found", value: { obj: id, descriptor: descriptor } };
  }
  if (expected_version != null) {
    if (existing_version != expected_version) {
      raise { code: "E_VERSION", message: "verb version conflict", value: { expected: expected_version, actual: existing_version } };
    }
  }
  // Compile (pure, no mutation).
  let compiled = compile_verb(source);
  let target_name = descriptor;
  if (existing != null) { target_name = existing["name"]; }
  if (compiled["ok"]) {
    let meta = compiled["metadata"];
    if (meta != null && has(meta, "name")) {
      let header_name = meta["name"];
      if (typeof(header_name) == "string") {
        if (typeof(target_name) == "string" && header_name != target_name) {
          let fail_name = { ok: false, dry_run: dry_run, slot: existing_slot, version: existing_version, metadata: meta, diagnostics: [{ severity: "error", code: "E_COMPILE", message: "verb header :" + header_name + " does not match install target :" + target_name }] };
          observe({ type: "programmer_check_failed", actor: actor, id: id, verb: descriptor, diagnostics: fail_name["diagnostics"], dry_run: dry_run, ts: now() });
          return fail_name;
        }
      }
    }
  }
  if (!compiled["ok"]) {
    let fail_compile = { ok: false, dry_run: dry_run, slot: existing_slot, version: existing_version, metadata: compiled["metadata"], diagnostics: compiled["diagnostics"] };
    observe({ type: "programmer_check_failed", actor: actor, id: id, verb: descriptor, diagnostics: compiled["diagnostics"], dry_run: dry_run, ts: now() });
    return fail_compile;
  }
  // Predict the slot/version that the install would land on.
  let projected_slot = existing_slot;
  let projected_version = 1;
  if (existing != null) {
    projected_version = existing_version + 1;
  } else {
    projected_slot = length(verbs(id)) + 1;
  }
  if (dry_run) {
    return { ok: true, dry_run: true, slot: projected_slot, version: projected_version, metadata: compiled["metadata"], diagnostics: [] };
  }
  // Apply: create stub if needed, then install code.
  if (existing == null) {
    let add_info = { name: target_name };
    let add_meta = compiled["metadata"];
    if (add_meta != null) {
      if (has(add_meta, "perms")) { add_info["perms"] = add_meta["perms"]; }
      if (has(add_meta, "arg_spec")) { add_info["arg_spec"] = add_meta["arg_spec"]; }
    }
    add_verb(id, add_info);
  }
  let errors = set_verb_code(id, target_name, source);
  if (length(errors) > 0) {
    // Should not happen — compile_verb already succeeded — but if the
    // header/name post-validation rejects, roll back the stub.
    if (existing == null) { try { delete_verb(id, target_name); } except err { } }
    let diag = [];
    for msg in errors { diag = diag + [{ severity: "error", code: "E_COMPILE", message: msg }]; }
    observe({ type: "programmer_check_failed", actor: actor, id: id, verb: descriptor, diagnostics: diag, dry_run: false, ts: now() });
    return { ok: false, dry_run: false, slot: projected_slot, version: existing_version, metadata: compiled["metadata"], diagnostics: diag };
  }
  let info_after = verb_info(id, target_name);
  observe({ type: "programmer_installed", actor: actor, id: id, verb: descriptor, slot: info_after["slot"], version: info_after["version"], ts: now() });
  return { ok: true, dry_run: false, slot: info_after["slot"], version: info_after["version"], metadata: compiled["metadata"], diagnostics: [] };
}

verb :set_verb_info(id, descriptor, opts) rxd {
  if (!has_flag(actor, "wizard")) {
    if (actor == $programmer) { raise { code: "E_PERM", message: "programmer class surface required", value: { actor: actor, surface: $programmer } }; }
    if (!isa(actor, $programmer)) { raise { code: "E_PERM", message: "programmer class surface required", value: { actor: actor, surface: $programmer } }; }
    if (!has_flag(actor, "programmer")) { raise { code: "E_PERM", message: "programmer flag required", value: actor }; }
  }
  // Metadata-only edit for aliases, arg spec, exposure flags, and perms.
  // Permission bits are changed here, not through source install. Does not
  // reinstall source. opts.dry_run=true validates without mutation.
  let dry_run = false;
  let expected_version = null;
  let info_overrides = {};
  if (typeof(opts) == "map") {
    if (has(opts, "dry_run")) { dry_run = opts["dry_run"]; }
    if (has(opts, "expected_version")) { expected_version = opts["expected_version"]; }
    if (has(opts, "aliases")) { info_overrides["aliases"] = opts["aliases"]; }
    if (has(opts, "perms")) { info_overrides["perms"] = opts["perms"]; }
    if (has(opts, "direct_callable")) { info_overrides["direct_callable"] = opts["direct_callable"]; }
    if (has(opts, "tool_exposed")) { info_overrides["tool_exposed"] = opts["tool_exposed"]; }
    if (has(opts, "arg_spec")) { info_overrides["arg_spec"] = opts["arg_spec"]; }
    if (has(opts, "owner")) { info_overrides["owner"] = opts["owner"]; }
  }
  let before = verb_info(id, descriptor);
  if (expected_version != null) {
    if (before["version"] != expected_version) {
      raise { code: "E_VERSION", message: "verb version conflict", value: { expected: expected_version, actual: before["version"] } };
    }
  }
  if (dry_run) {
    return { ok: true, dry_run: true, id: id, slot: before["slot"], version: before["version"] + 1, before: before, after: before };
  }
  let updated = set_verb_info(id, descriptor, info_overrides);
  let after = verb_info(id, descriptor);
  observe({ type: "programmer_verb_info_changed", actor: actor, id: id, verb: descriptor, slot: updated["slot"], version: updated["version"], ts: now() });
  return { ok: true, dry_run: false, id: id, slot: updated["slot"], version: updated["version"], before: before, after: after };
}

verb :set_property_info(id, name, opts) rxd {
  if (!has_flag(actor, "wizard")) {
    if (actor == $programmer) { raise { code: "E_PERM", message: "programmer class surface required", value: { actor: actor, surface: $programmer } }; }
    if (!isa(actor, $programmer)) { raise { code: "E_PERM", message: "programmer class surface required", value: { actor: actor, surface: $programmer } }; }
    if (!has_flag(actor, "programmer")) { raise { code: "E_PERM", message: "programmer flag required", value: actor }; }
  }
  // Define/update property metadata, defaults, perms, and type hints. This is
  // programmer authority, not the builder value-setting surface.
  let dry_run = false;
  let mode = "upsert";
  if (typeof(opts) == "map") {
    if (has(opts, "dry_run")) { dry_run = opts["dry_run"]; }
    if (has(opts, "mode")) { mode = opts["mode"]; }
  }
  if (mode != "upsert" && mode != "define" && mode != "update" && mode != "delete") {
    raise { code: "E_INVARG", message: "unknown property-info mode", value: mode };
  }
  let existing = null;
  try { existing = property_info(id, name); } except err { existing = null; }
  // The substrate raises E_PROPNF when looking up a non-defined property; if
  // the def lives on a parent class, property_info still returns it. For mode
  // semantics we want to treat "defined on this object directly" as the
  // existence test.
  let exists_locally = false;
  if (existing != null) {
    if (existing["defined_on"] == id) { exists_locally = true; }
  }
  if (mode == "define" && exists_locally) {
    raise { code: "E_INVARG", message: "property already exists", value: { obj: id, property: name } };
  }
  if ((mode == "update" || mode == "delete") && !exists_locally) {
    raise { code: "E_PROPNF", message: "property not defined on object", value: { obj: id, property: name } };
  }
  if (mode == "delete") {
    let delete_before = existing;
    if (dry_run) { return { ok: true, dry_run: true, id: id, name: name, deleted: true, before: delete_before }; }
    set_task_perms(actor);
    delete_property(id, name);
    return { ok: true, dry_run: false, id: id, name: name, deleted: true, before: delete_before };
  }
  let perms_opt = "rw";
  if (existing != null) { perms_opt = existing["perms"]; }
  let owner_opt = actor;
  if (existing != null) { owner_opt = existing["owner"]; }
  let type_opt = null;
  if (existing != null) { type_opt = existing["type_hint"]; }
  let default_value = null;
  if (typeof(opts) == "map") {
    if (has(opts, "perms")) { perms_opt = opts["perms"]; }
    if (has(opts, "owner")) { owner_opt = opts["owner"]; }
    if (has(opts, "type_hint")) { type_opt = opts["type_hint"]; }
    if (has(opts, "default")) { default_value = opts["default"]; }
  }
  let info_map = { owner: owner_opt, perms: perms_opt };
  if (type_opt != null) { info_map["type_hint"] = type_opt; }
  let before = existing;
  if (dry_run) {
    let projected = { name: name, owner: owner_opt, perms: perms_opt, defined_on: id, type_hint: type_opt };
    return { ok: true, dry_run: true, id: id, name: name, before: before, after: projected };
  }
  set_task_perms(actor);
  if (!exists_locally) {
    add_property(id, name, default_value, info_map);
  } else {
    set_property_info(id, name, info_map);
  }
  let after = property_info(id, name);
  return { ok: true, dry_run: false, id: id, name: name, version: after["version"], before: before, after: after };
}

