verb :eval(source, opts) rxd {
  /* Compile and run a Woo expression or statement block under the calling
   * programmer's authority. This is a strict superset of `woo_call`: any
   * verb can be invoked as `;target:verb(arg1, arg2)`, any readable property
   * read as `;obj.prop`, and arbitrary computation expressed inline. Ideal
   * for chat-as-CLI use and for programmer agents that need to script the
   * world without round-tripping through individual MCP tools.
   *
   * Args:
   *   source: Woo source text. Default mode wraps as `return <source>;`,
   *           so an expression like `the_chatroom:say("hi")` is fine.
   *           Pass opts.mode="stmts" to run a multi-statement body verbatim.
   *   opts.mode: "expr" (default) | "stmts"
   *   opts.dry_run: true compiles only, returns diagnostics, runs nothing.
   *
   * Returns a map on success or compile failure:
   *   { ok: true,  dry_run, value }                          // success
   *   { ok: false, dry_run, diagnostics: [{severity,code,message,...}] }  // compile error
   *
   * Runtime errors thrown by the body propagate as ordinary errors so the
   * outer direct-call transaction rolls back state, placement, and parked
   * tasks. A failed `;create(...) ; return 1/0;` does not leave the created
   * object behind. (LambdaCore @eval renders the traceback into chat; here
   * the chat layer renders the propagated error frame.)
   *
   * Authority: the wrapped code runs with `progr = caller`, not the catalog
   * installer that owns this verb, so eval cannot escalate. Gated on
   * wizard-or-progbit + $programmer ancestry; non-programmers get E_PERM.
   *
   * Examples:
   *   ;1 + 2                                    // -> {ok:true,value:3}
   *   ;the_chatroom:say("hello")                // call a verb
   *   ;;let x = 0; for i in [1,2,3] { x = x + i; } return x;   // mode="stmts"
   */
  if (!has_flag(actor, "wizard")) {
    if (actor == $programmer) { raise { code: "E_PERM", message: "programmer class surface required", value: { actor: actor, surface: $programmer } }; }
    if (!isa(actor, $programmer)) { raise { code: "E_PERM", message: "programmer class surface required", value: { actor: actor, surface: $programmer } }; }
    if (!has_flag(actor, "programmer")) { raise { code: "E_PERM", message: "programmer flag required", value: actor }; }
  }
  let result = programmer_eval(source, opts);
  if (result["ok"]) {
    if (result["dry_run"]) {
      tell(actor, "(dry_run ok)");
    } else {
      tell(actor, "=> " + to_string(result["value"]));
    }
  } else {
    let line = "compile error";
    let diags = result["diagnostics"];
    if (typeof(diags) == "list" && length(diags) > 0) {
      let d = diags[1];
      line = "compile error: " + d["code"] + " " + d["message"];
    }
    tell(actor, line);
  }
  return result;
}

verb :force_recycle(id, opts) rxd {
  // Wizard-only force_recycle. Bypasses most §RC6 reserved-list checks
  // (universal classes other than $system/$root/$nowhere; live actors,
  // whose sessions are terminated as part of the call) and the §RC3a
  // empty-children safety check. Routes through the unified `recycle`
  // builtin with force_reserved + force.
  //
  // The substrate gates RC2 authority on `progr` (the verb's effective
  // principal), so a wrapper verb running with wizard progr could be
  // invoked by any actor. We additionally gate on `actor` here so a
  // non-wizard caller cannot bypass §RC6 by calling this verb. This is
  // the LambdaCore @recycle convention: substrate trusts progr; the
  // user-facing wrapper trusts actor. Audited as a force_recycle
  // wizard_action; emits a wiz_force_recycle observation. Use sparingly —
  // for irreversible world-teardown and migration only.
  "the_perm":requires_wizard(actor, "wizard authority required for force_recycle");
  let merged = opts;
  if (typeof(merged) != "map") { merged = {}; }
  merged["force_reserved"] = true;
  merged["force"] = true;
  return recycle(id, merged);
}

verb :verbs_command(dobjstr) rxd {
