    tell(actor, "Usage: @verbs <object>");
    return null;
  }
  let thing = $match:match_object(dobjstr);
  if ($command_utils:object_match_failed(thing, dobjstr)) {
    return null;
  }
  // L17 LambdaCore: ";verbs(<id>) => {...}" — eval-shaped output that the
  // reader can re-type. Mirror that shape; ids are paste-able per the
