verb :property_command(argstr) rxd {
  // LambdaCore $prog:@property (#217), faithfully ported as far as the
  // `<obj>.<prop> [<value>]` shape. LambdaCore's full L21-49 parses an
  // optional <perms> <owner> tail via prefix_to_value and player_match
  // — that level is deferred until $string_utils:prefix_to_value lands.
  // Until then the verb rejects anything beyond the <value> token so a
  // typed `@property #x.foo 0 r` doesn't silently store "0 r" as the
  // value with default perms (the partial-port footgun).
  //
  // Divergence (1): the value parser handles a leading double-quote by
  // gathering subsequent space-separated tokens up to a matching
  // close-quote so `@property #x.title "hello world"` round-trips.
  // LambdaCore L25 does this through prefix_to_value; the woo helper
  // `$string_utils:to_value` strips the surrounding quotes once we hand
  // it the full quoted token.
  if (!has_flag(actor, "wizard")) {
    if (actor == $programmer) { raise { code: "E_PERM", message: "programmer class surface required", value: { actor: actor, surface: $programmer } }; }
    if (!isa(actor, $programmer)) { raise { code: "E_PERM", message: "programmer class surface required", value: { actor: actor, surface: $programmer } }; }
    if (!has_flag(actor, "programmer")) { raise { code: "E_PERM", message: "programmer flag required", value: actor }; }
  }
  let usage = "Usage: @property <object>.<prop-name> [<init_value>]";
  if (typeof(argstr) != "string" || str_trim(argstr) == "") {
    tell(actor, usage);
    return null;
  }
  let raw_tokens = str_split(str_trim(argstr), " ");
  let tokens = [];
  for t in raw_tokens {
    let s = str_trim(t);
    if (s != "") { tokens = tokens + [s]; }
  }
  if (length(tokens) == 0) { tell(actor, usage); return null; }
  let spec = $code_utils:parse_propref(tokens[1]);
  if (typeof(spec) != "list") { tell(actor, usage); return null; }
  let obj_str = spec[1];
  let pname = spec[2];
  let object = $match:match_object(obj_str);
  if ($command_utils:object_match_failed(object, obj_str)) {
    return null;
  }
  let value = 0;
  let total = length(tokens);
  if (total >= 2) {
    let q = str_char(34);
    let first = tokens[2];
    let value_str = first;
    let consumed_through = 2;
    // Quoted-value branch: if the first value token starts with " and
    // either doesn't end with " on its own (the open quote spans
    // multiple words) or DOES end with " (single-word quoted), gather
    // until balanced and use the entire run as the value-string.
    if (str_slice(first, 1, 1) == q) {
      let flen = length(first);
      let already_closed = false;
      // A token like `"foo"` is self-balanced when length>=2 and last
      // char is also a quote.
      if (flen >= 2) {
        if (str_slice(first, flen, flen) == q) { already_closed = true; }
      }
      if (!already_closed) {
        let i = 3;
        let acc = first;
        let found_close = false;
        while (i <= total) {
          acc = acc + " " + tokens[i];
          let alen = length(tokens[i]);
          if (alen >= 1) {
            if (str_slice(tokens[i], alen, alen) == q) {
              found_close = true;
              consumed_through = i;
              i = total + 1;
            }
          }
          if (!found_close) { i = i + 1; }
        }
        if (!found_close) {
          tell(actor, "Unterminated quoted value: " + first);
          return null;
        }
        value_str = acc;
      }
    }
    if (total > consumed_through) {
      tell(actor, "Sorry, the <perms> and <owner> tail isn't ported yet — use @property <obj>.<prop> [<value>], then @chmod / @chown.");
      return null;
    }
    let parsed = $string_utils:to_value(value_str);
    if (!parsed[1]) {
      tell(actor, "Syntax error in initial value: " + value_str);
      return null;
    }
    value = parsed[2];
  }
  let info = { owner: actor, perms: "rc" };
  try {
    add_property(object, pname, value, info);
    tell(actor, "Property added with value " + to_string(value) + ".");
  } except err {
    if (err["code"] == "E_INVARG") {
      tell(actor, "Property " + obj_str + "." + pname + " already exists.");
    } else {
      tell(actor, err["message"]);
    }
    return err;
  }
  return { ok: true, id: object, name: pname, value: value };
}

