verb :verb_command(argstr) rxd {
  // LambdaCore $prog:@verb (#217), faithfully ported. Adds a new verb
  // to an object. Source body starts as a no-op stub; use @program /
  // `set_verb_code` to install code afterwards.
  //
  // Divergence (1): LambdaCore L31 falls back to player.prog_option(
  // "verb_args"); woo doesn't carry that option, so the woo default is
  // the LambdaCore L32 fallback — {"none","none","none"}. Partial
  // specs (one or two tokens) are padded to length 3 with "none" the
  // same way LambdaCore does after parse_argspec.
  //
  // Divergence (2): LambdaCore L42-44 also accepts a trailing
  // <perms> [<owner>] tail. That requires $string_utils:prefix_to_value
  // and $string_utils:match_player to be ported; the initial port
  // rejects extra tokens explicitly so a typed
  // `@verb obj:foo this none this rxd wiz` doesn't silently lose
  // perms/owner.
  if (!has_flag(actor, "wizard")) {
    if (actor == $programmer) { raise { code: "E_PERM", message: "programmer class surface required", value: { actor: actor, surface: $programmer } }; }
    if (!isa(actor, $programmer)) { raise { code: "E_PERM", message: "programmer class surface required", value: { actor: actor, surface: $programmer } }; }
    if (!has_flag(actor, "programmer")) { raise { code: "E_PERM", message: "programmer flag required", value: actor }; }
  }
  let usage = "Usage: @verb <object>:<verb-name>[,<alias>...] [<dobj> [<prep> [<iobj>]]]";
  if (typeof(argstr) != "string" || str_trim(argstr) == "") {
    tell(actor, usage);
    return null;
  }
  let raw_tokens = str_split(str_trim(argstr), " ");
  let tokens = [];
  for t in raw_tokens {
    let s = str_trim(t);
    if (s != "") { tokens = tokens + [s]; }
  }
  if (length(tokens) < 1) { tell(actor, usage); return null; }
  let spec = $code_utils:parse_verbref(tokens[1]);
  if (typeof(spec) != "list") { tell(actor, usage); return null; }
  let obj_str = spec[1];
  let verb_def = spec[2];
  let object = $match:match_object(obj_str);
  if ($command_utils:object_match_failed(object, obj_str)) { return null; }
  let arg_tokens = [];
  let ntot = length(tokens);
  if (ntot > 1) { for i in [2..ntot] { arg_tokens = arg_tokens + [tokens[i]]; } }
  let parsed = $code_utils:parse_argspec(arg_tokens);
  if (typeof(parsed) == "string") { tell(actor, parsed); return null; }
  let verbargs = parsed[1];
  let leftover = parsed[2];
  // LambdaCore L32 pads partial argspecs to length 3 with "none". Mirror
  // exactly: `@verb obj:foo this` lands as ["this","none","none"];
  // `@verb obj:foo` (no spec) lands as ["none","none","none"].
  while (length(verbargs) < 3) { verbargs = verbargs + ["none"]; }
  if (length(leftover) > 0) {
    tell(actor, "Sorry, the <perms> and <owner> tail isn't ported yet — use @verb <obj>:<name> [<dobj> <prep> <iobj>], then @chmod / @chown.");
    return null;
  }
  let names = str_split(verb_def, ",");
  let trimmed_names = [];
  for n in names { let nt = str_trim(n); if (nt != "") { trimmed_names = trimmed_names + [nt]; } }
  if (length(trimmed_names) == 0) { tell(actor, usage); return null; }
  let main_name = trimmed_names[1];
  let aliases = [];
  let nlen = length(trimmed_names);
  if (nlen > 1) { for i in [2..nlen] { aliases = aliases + [trimmed_names[i]]; } }
  let default_perms = "rd";
  if (verbargs[1] == "this") { if (verbargs[2] == "none") { if (verbargs[3] == "this") { default_perms = "rxd"; } } }
  let info = { name: main_name, owner: actor, perms: default_perms };
  if (length(aliases) > 0) { info["aliases"] = aliases; }
  info["arg_spec"] = { args: [], command: { dobj: verbargs[1], prep: verbargs[2], iobj: verbargs[3] } };
  let result = null;
  try {
    result = add_verb(object, info);
  } except err {
    tell(actor, err["message"]);
    return err;
  }
  tell(actor, "Verb added (slot " + to_string(result["slot"]) + ").");
  return { ok: true, id: object, name: main_name, slot: result["slot"] };
}

verb :args_command(argstr) rxd {
  // LambdaCore $prog:@args (#217), faithfully ported. Sets the
  // dobj/prep/iobj specifier on an existing verb. With no spec given,
  // displays the current spec (LambdaCore L30-31).
  //
  // Divergence (1): LambdaCore verbs all carry a `command` (dobj/prep/iobj)
  // arg-spec. woo verbs that are exclusively direct-callable (most
  // $programmer:* MCP tools) carry only a positional `args` list. The
  // display branch renders either shape; the mutation branch errors out
  // on a non-command verb because @args is the wrong tool — use
  // @program / install_verb to change a non-command verb's signature.
  //
  // Divergence (2): the LambdaCore @args# variant addresses the verb by
  // 1-indexed slot. Not exposed as a separate verb; @args accepts
  // either name or slot via $code_utils:nth_verb_name when needed
  // (deferred until called for).
  if (!has_flag(actor, "wizard")) {
    if (actor == $programmer) { raise { code: "E_PERM", message: "programmer class surface required", value: { actor: actor, surface: $programmer } }; }
    if (!isa(actor, $programmer)) { raise { code: "E_PERM", message: "programmer class surface required", value: { actor: actor, surface: $programmer } }; }
    if (!has_flag(actor, "programmer")) { raise { code: "E_PERM", message: "programmer flag required", value: actor }; }
  }
  let usage = "Usage: @args <object>:<verb> [<dobj> <prep> <iobj>]";
  if (typeof(argstr) != "string" || str_trim(argstr) == "") { tell(actor, usage); return null; }
  let raw_tokens = str_split(str_trim(argstr), " ");
  let tokens = [];
  for t in raw_tokens { let s = str_trim(t); if (s != "") { tokens = tokens + [s]; } }
  if (length(tokens) < 1) { tell(actor, usage); return null; }
  let spec = $code_utils:parse_verbref(tokens[1]);
  if (typeof(spec) != "list") { tell(actor, usage); return null; }
  let obj_str = spec[1];
  let vname = spec[2];
  let object = $match:match_object(obj_str);
  if ($command_utils:object_match_failed(object, obj_str)) { return null; }
  let info = null;
  try { info = verb_info(object, vname); } except err {
    if (err["code"] == "E_VERBNF") { tell(actor, "That object does not have a verb with that name."); return err; }
    tell(actor, err["message"]); return err;
  }
  let arg_tokens = [];
  let ntot = length(tokens);
  if (ntot > 1) { for i in [2..ntot] { arg_tokens = arg_tokens + [tokens[i]]; } }
  let parsed = $code_utils:parse_argspec(arg_tokens);
  if (typeof(parsed) == "string") { tell(actor, parsed); return null; }
  let verbargs = parsed[1];
  let leftover = parsed[2];
  if (length(leftover) > 0) {
    tell(actor, "Extra tokens: " + str_join(leftover, " "));
    return null;
  }
  // Display branch: no spec → describe whatever the verb has, command or args.
  if (length(verbargs) == 0) {
    let argspec = info["arg_spec"];
    let suffix = "()";
    if (typeof(argspec) == "map") {
      if (has(argspec, "command")) {
        let c = argspec["command"];
        suffix = c["dobj"] + "  " + c["prep"] + "  " + c["iobj"];
      } else {
        if (has(argspec, "args")) {
          let a = argspec["args"];
          if (typeof(a) == "list" && length(a) > 0) {
            suffix = "(" + str_join(a, ", ") + ")";
          }
        }
      }
    }
    tell(actor, info["name"] + "  " + suffix);
    return info;
  }
  if (length(verbargs) < 3) {
    tell(actor, "Argument spec must be three tokens: <dobj> <prep> <iobj>");
    return null;
  }
  // Mutation branch: requires a command-shaped argspec. Refuse politely
  // for verbs that are direct-callable only.
  let cur_spec = info["arg_spec"];
  if (typeof(cur_spec) != "map" || !has(cur_spec, "command")) {
    tell(actor, "That verb is direct-callable only (no command shape) — use @program / install_verb to add a command argspec.");
    return null;
  }
  let new_arg_spec = { args: cur_spec["args"], command: { dobj: verbargs[1], prep: verbargs[2], iobj: verbargs[3] } };
  try {
    set_verb_info(object, vname, { arg_spec: new_arg_spec });
    tell(actor, "Verb arguments changed.");
  } except err {
    tell(actor, err["message"]); return err;
  }
  return { ok: true, id: object, name: vname };
}

