verb :rename_command(dobjstr, iobjstr) rxd {
  // LambdaCore $root:@rename (#6, on $player), faithfully ported.
  // Three branches dispatched on the dobjstr shape:
  //   <obj>:<verb>   — rename a verb (set_verb_info name)
  //   <obj>.<prop>   — rename a property (DEFERRED; see below)
  //   <obj>          — rename an object (set_object_name)
  //
  // Divergence (1): woo's set_property_info doesn't support in-place
  // rename — child objects with override values key by old name and
  // would need migration. The property branch returns a clear pointer
  // rather than half-implementing it.
  //
  // Divergence (2): LambdaCore's object branch goes through
  // $building_utils:set_names, which accepts a comma-separated
  // "name,alias,..." form and updates aliases as a side effect, AND
  // calls $player_db:why_bad_name to reject names that contain
  // whitespace, control characters, or are too long. Neither
  // $building_utils:set_names nor $player_db is ported yet; the verb
  // applies a minimal validation tier inline (no whitespace, no control
  // chars, length cap) so callers don't accidentally store names that
  // LambdaCore's command parser would refuse to round-trip.
  if (!has_flag(actor, "wizard")) {
    if (actor == $programmer) { raise { code: "E_PERM", message: "programmer class surface required", value: { actor: actor, surface: $programmer } }; }
    if (!isa(actor, $programmer)) { raise { code: "E_PERM", message: "programmer class surface required", value: { actor: actor, surface: $programmer } }; }
    if (!has_flag(actor, "programmer")) { raise { code: "E_PERM", message: "programmer flag required", value: actor }; }
  }
  let usage = "Usage: @rename <object> to <name>  |  <obj>:<verb> to <name>  |  <obj>.<prop> to <name>";
  if (typeof(dobjstr) != "string" || dobjstr == "") { tell(actor, usage); return null; }
  if (typeof(iobjstr) != "string" || str_trim(iobjstr) == "") { tell(actor, usage); return null; }
  let new_name = str_trim(iobjstr);
  let vspec = $code_utils:parse_verbref(dobjstr);
  if (typeof(vspec) == "list") {
    let v_object = $match:match_object(vspec[1]);
    if ($command_utils:object_match_failed(v_object, vspec[1])) { return null; }
    let vname = vspec[2];
    try {
      set_verb_info(v_object, vname, { name: new_name });
      tell(actor, "Verb name changed.");
    } except err {
      if (err["code"] == "E_VERBNF") { tell(actor, "That object does not define that verb."); return err; }
      tell(actor, err["message"]); return err;
    }
    return { ok: true, kind: "verb", id: v_object, old: vname, new: new_name };
  }
  let pspec = $code_utils:parse_propref(dobjstr);
  if (typeof(pspec) == "list") {
    tell(actor, "Sorry, property rename isn't ported yet — use @property to add the new name and @rmproperty to remove the old (children with overrides will need migration).");
    return null;
  }
  let o_object = $match:match_object(dobjstr);
  if ($command_utils:object_match_failed(o_object, dobjstr)) { return null; }
  if (str_index(new_name, ",") > 0) {
    tell(actor, "Sorry, the comma-separated `name,alias,...` shape isn't ported yet — set object name with @rename, aliases with @set obj.aliases.");
    return null;
  }
  // Inline validation tier (LambdaCore $building_utils:set_names +
  // $player_db:why_bad_name surrogate): reject whitespace and control
  // chars, cap length. Non-empty already enforced by str_trim above.
  if (length(new_name) > 64) {
    tell(actor, "Name too long (max 64 characters).");
    return null;
  }
  if (str_index(new_name, " ") > 0) {
    tell(actor, "Name cannot contain whitespace.");
    return null;
  }
  if (str_index(new_name, "\t") > 0) {
    tell(actor, "Name cannot contain whitespace.");
    return null;
  }
  if (str_index(new_name, "\n") > 0) {
    tell(actor, "Name cannot contain whitespace.");
    return null;
  }
  let old_name = o_object.name;
  try {
    set_object_name(o_object, new_name);
  } except err {
    tell(actor, err["message"]); return err;
  }
  let id_str = o_object;
  if (!str_starts(id_str, "$")) { id_str = "#" + id_str; }
  let q = str_char(34);
  tell(actor, "Name of " + id_str + " (" + old_name + ") changed to " + q + new_name + q + ".");
  return { ok: true, kind: "object", id: o_object, old: old_name, new: new_name };
}

verb :list_command(dobjstr) rxd {
  // LambdaCore $prog:@list (#217), STUB port. The full LambdaCore @list
  // (line ranges, `with parens`, `without numbers`, `all` to walk the
  // ancestor chain, argspec disambiguation) is 142 lines of arg-parsing;
  // the stub just dumps source verbatim with a header line and 1-based
  // line numbers. Range and option support land when a user reaches
  // for them.
  //
  // Divergence (1): the header line in LambdaCore renders verb_args
  // unconditionally (every LambdaCore verb has dobj/prep/iobj). woo
  // verbs that are direct-callable only carry a positional `args` list
  // instead; the header falls back to "(arg1, arg2, ...)" so @list
  // works on either shape.
  if (!has_flag(actor, "wizard")) {
    if (actor == $programmer) { raise { code: "E_PERM", message: "programmer class surface required", value: { actor: actor, surface: $programmer } }; }
    if (!isa(actor, $programmer)) { raise { code: "E_PERM", message: "programmer class surface required", value: { actor: actor, surface: $programmer } }; }
    if (!has_flag(actor, "programmer")) { raise { code: "E_PERM", message: "programmer flag required", value: actor }; }
  }
  let usage = "Usage: @list <object>:<verb>";
  if (typeof(dobjstr) != "string" || dobjstr == "") { tell(actor, usage); return null; }
  let spec = $code_utils:parse_verbref(dobjstr);
  if (typeof(spec) != "list") { tell(actor, usage); return null; }
  let obj_str = spec[1];
  let vname = spec[2];
  let object = $match:match_object(obj_str);
  if ($command_utils:object_match_failed(object, obj_str)) { return null; }
  let info = null;
  try { info = verb_info(object, vname); } except err {
    if (err["code"] == "E_VERBNF") { tell(actor, "That object does not define that verb."); return err; }
    tell(actor, err["message"]); return err;
  }
  let code = "";
  try { code = verb_code(object, vname); } except err {
    tell(actor, err["message"]); return err;
  }
  let id_str = object;
  if (!str_starts(id_str, "$")) { id_str = "#" + id_str; }
  let argstr_render = "()";
  let argspec = info["arg_spec"];
  if (typeof(argspec) == "map") {
    if (has(argspec, "command")) {
      let c = argspec["command"];
      argstr_render = c["dobj"] + "  " + c["prep"] + "  " + c["iobj"];
    } else {
      if (has(argspec, "args")) {
        let a = argspec["args"];
        if (typeof(a) == "list" && length(a) > 0) {
          argstr_render = "(" + str_join(a, ", ") + ")";
        }
      }
    }
  }
  let header = id_str + ":" + info["name"] + "   " + argstr_render + "   " + info["perms"];
  tell(actor, header);
  let lines = str_split(code, "\n");
  let total = length(lines);
  if (total > 0) {
    for i in [1..total] {
      let prefix = " ";
      if (i >= 10) { prefix = ""; }
      tell(actor, prefix + to_string(i) + ":  " + lines[i]);
    }
  }
  return { ok: true, id: object, name: vname, line_count: total };
}

verb :chmod_command(argstr) rxd {
  // LambdaCore $prog:@chmod (#217), faithfully ported. Three shapes
  // dispatched on the target token:
  //   <obj>:<verb>   — set verb perms
  //   <obj>.<prop>   — set property perms
  //   <obj>          — set object flags (DEFERRED)
  // <perms> may be absolute (`rxd`) or relative (`+w-x`); see
  // $perm:apply.
  //
  // Divergence (1): woo doesn't carry a uniform per-object r/w/f flag
  // string; the wizard/programmer/etc. flags are managed via has_flag.
  // The object branch rejects with a pointer to has_flag rather than
  // half-implementing.
  //
  // Divergence (2): woo's chat-parser splits a command like
  // "@chmod #X:foo rxd" into (dobj="#X:foo rxd", prep=none) when no
  // preposition is present. The verb takes the whole tail as a single
  // `argstr` and tokenizes itself; LambdaCore's args[1]/args[2] indexing
  // works the same way.
  if (!has_flag(actor, "wizard")) {
    if (actor == $programmer) { raise { code: "E_PERM", message: "programmer class surface required", value: { actor: actor, surface: $programmer } }; }
    if (!isa(actor, $programmer)) { raise { code: "E_PERM", message: "programmer class surface required", value: { actor: actor, surface: $programmer } }; }
    if (!has_flag(actor, "programmer")) { raise { code: "E_PERM", message: "programmer flag required", value: actor }; }
  }
  let usage = "Usage: @chmod <object-or-property-or-verb> <permissions>";
  if (typeof(argstr) != "string" || str_trim(argstr) == "") { tell(actor, usage); return null; }
  let raw_tokens = str_split(str_trim(argstr), " ");
  let tokens = [];
  for t in raw_tokens { let s = str_trim(t); if (s != "") { tokens = tokens + [s]; } }
  if (length(tokens) != 2) { tell(actor, usage); return null; }
  let target = tokens[1];
  let new_perms = tokens[2];
  let vspec = $code_utils:parse_verbref(target);
  if (typeof(vspec) == "list") {
    let v_object = $match:match_object(vspec[1]);
    if ($command_utils:object_match_failed(v_object, vspec[1])) { return null; }
    let vname = vspec[2];
    let vinfo = null;
    try { vinfo = verb_info(v_object, vname); } except err {
      if (err["code"] == "E_VERBNF") { tell(actor, "That object does not define that verb."); return err; }
      tell(actor, err["message"]); return err;
    }
    let v_final = "the_perm":apply(vinfo["perms"], new_perms);
    let vq = str_char(34);
    try {
      set_verb_info(v_object, vname, { perms: v_final });
      tell(actor, "Verb permissions set to " + vq + v_final + vq + ".");
    } except err {
      if (err["code"] == "E_INVARG") { tell(actor, vq + v_final + vq + " is not a valid permissions string for a verb."); return err; }
      tell(actor, err["message"]); return err;
    }
    return { ok: true, kind: "verb", id: v_object, name: vname, perms: v_final };
  }
  if (str_index(target, ".") > 0) {
    let pspec = $code_utils:parse_propref(target);
    if (typeof(pspec) == "list") {
      let p_object = $match:match_object(pspec[1]);
      if ($command_utils:object_match_failed(p_object, pspec[1])) { return null; }
      let pname = pspec[2];
      let pinfo = null;
      try { pinfo = property_info(p_object, pname); } except err {
        if (err["code"] == "E_PROPNF") { tell(actor, "That object does not have that property."); return err; }
        tell(actor, err["message"]); return err;
      }
      let p_final = "the_perm":apply(pinfo["perms"], new_perms);
      let pq = str_char(34);
      try {
        set_property_info(p_object, pname, { perms: p_final });
        tell(actor, "Property permissions set to " + pq + p_final + pq + ".");
      } except err {
        if (err["code"] == "E_INVARG") { tell(actor, pq + p_final + pq + " is not a valid permissions string for a property."); return err; }
        tell(actor, err["message"]); return err;
      }
      return { ok: true, kind: "property", id: p_object, name: pname, perms: p_final };
    }
  }
  let o_object = $match:match_object(target);
  if ($command_utils:object_match_failed(o_object, target)) { return null; }
  tell(actor, "Sorry, object-level @chmod (r/w/f flags) isn't ported — woo manages object flags via has_flag and wizard-only setters.");
  return null;
}

verb :chown_command(argstr) rxd {
  // LambdaCore $wiz:@chown (#218), faithfully ported. Wizard-only —
  // verb/property owner is the execution authority, so changing it is
  // a privilege escalation primitive. Three shapes mirror @chmod.
  //
  // Divergence (1): LambdaCore's object branch goes through
  // $wiz_utils:set_owner. woo doesn't expose set_object_owner from
  // woocode (substrate change needed); the object branch is rejected
  // with a clear pointer.
  //
  // Divergence (2): woo's chat-parser splits a command like
  // "@chown #X:foo #Y" into (dobj="#X:foo #Y", prep=none). The verb
  // takes the whole tail as a single `argstr` and tokenizes itself.
  // LambdaCore's `setremove(args, "to")` is mirrored by stripping a
  // leading "to" from the second token here.
  //
  // Divergence (3): LambdaCore L12 resolves the new owner via
  // $string_utils:match_player. woo doesn't have that helper ported
  // yet; the verb requires the resolved object to descend from
  // $player so a non-player object cannot be assigned ownership of a
  // verb (whose owner is its execution authority `progr`).
  "the_perm":requires_wizard(actor, "wizard authority required for @chown");
  let usage = "Usage: @chown <object-or-property-or-verb> <owner>";
  if (typeof(argstr) != "string" || str_trim(argstr) == "") { tell(actor, usage); return null; }
  let raw_tokens = str_split(str_trim(argstr), " ");
  let tokens = [];
  for t in raw_tokens { let s = str_trim(t); if (s != "") { tokens = tokens + [s]; } }
  let filtered = [];
  for tk in tokens { if (tk != "to") { filtered = filtered + [tk]; } }
  tokens = filtered;
  if (length(tokens) != 2) { tell(actor, usage); return null; }
  let target = tokens[1];
  let owner_str = tokens[2];
  let new_owner = $match:match_object(owner_str);
  if ($command_utils:object_match_failed(new_owner, owner_str)) { return null; }
  if (!isa(new_owner, $player)) {
    tell(actor, "Owner must be a player object.");
    return null;
  }
  let vspec = $code_utils:parse_verbref(target);
  if (typeof(vspec) == "list") {
    let v_object = $match:match_object(vspec[1]);
    if ($command_utils:object_match_failed(v_object, vspec[1])) { return null; }
    let vname = vspec[2];
    try {
      set_verb_info(v_object, vname, { owner: new_owner });
      tell(actor, "Verb owner set.");
    } except err {
      if (err["code"] == "E_VERBNF") { tell(actor, "That object does not define that verb."); return err; }
      tell(actor, err["message"]); return err;
    }
    return { ok: true, kind: "verb", id: v_object, name: vname, owner: new_owner };
  }
  if (str_index(target, ".") > 0) {
    let pspec = $code_utils:parse_propref(target);
    if (typeof(pspec) == "list") {
      let p_object = $match:match_object(pspec[1]);
      if ($command_utils:object_match_failed(p_object, pspec[1])) { return null; }
      let pname = pspec[2];
      try {
        set_property_info(p_object, pname, { owner: new_owner });
        tell(actor, "Property owner set.");
      } except err {
        if (err["code"] == "E_PROPNF") { tell(actor, "That object does not have that property."); return err; }
        tell(actor, err["message"]); return err;
      }
      return { ok: true, kind: "property", id: p_object, name: pname, owner: new_owner };
    }
  }
  tell(actor, "Sorry, object @chown (changing object owner) isn't ported — needs a wizard-only set_object_owner builtin which is a separate substrate change.");
  return null;
}

